  ('disabled-6f0ba476-moex-00171', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-113-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '乙公司於 X3 年初平價發行$500,000 可轉換公司債，轉換價格為$25。X6 年12月1日為誘導轉換為普通股（每股面額$5），將轉換價格降為$20， 當時乙公司股價為$30。X6年無公司債進行轉換，則乙公司修改轉換價格 對X6年度綜合損益總額之影響為：（不考慮所得稅影響）', '["減少$75,000", "減少$150,000", "減少$225,000", "減少$300,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:28+00:00", "source_pdf_sha1": "96d5295faf56", "answer_pdf_sha1": "2f6eb3654efb", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "305", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00172', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-113-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '寶島文具公司於X9年9月1日將300本筆記本委託東風文具店代銷，約 定銷售期間為 3 個月。每本筆記本的售價設定為$100，成本為$70，合約 中明確規定東風文具店每銷售一本筆記本將獲得$5的佣金。代銷期間內， 東風文具店共銷出200本，寶島文具公司於X9年12月31日收回未售出 的筆記本和書款，並結算支付給東風文具店的佣金。根據此情況，試問寶 島文具公司於X9年9月1日應認列的銷貨收入為：', '["$20,000", "$19,000", "$1,000", "$0"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:28+00:00", "source_pdf_sha1": "96d5295faf56", "answer_pdf_sha1": "2f6eb3654efb", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "305", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00173', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-113-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'essay', '甲死亡後，其繼承人有乙、丙、丁、戊等 4 人，並由乙保管甲所遺留
之現金新臺幣（下同）1,000 萬元、房屋及其坐落之土地各一筆。今
國稅局核課甲之遺產稅為 400 萬元，且業已通知甲之上開繼承人依
限繳納，然丙、丁、戊 3人均不理會，且不願意分割遺產，乙遂以自
己之固有財產先行繳納完畢。乙以自己之固有財產繳納遺產稅後，得
否依民法規定，逕行訴請丙、丁、戊各應給付乙100 萬元？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:28+00:00", "source_pdf_sha1": "00563b442671", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "305", "s": "0402", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00174', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-113-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'essay', '甲夫與乙妻結婚後，因時常意見不合而爭吵，某日甲夫與單身女子丙
發生婚外情，經乙妻捉姦在床，乙遂以甲與丙合意性交為由，訴請甲、
丙二人，應負非財產上損害賠償責任新臺幣 200萬元，試申論其請求
權之基礎為何？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:28+00:00", "source_pdf_sha1": "00563b442671", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "305", "s": "0402", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00175', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-113-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '下列何者是形成權？', '["民法第144條消滅時效抗辯權", "民法第359條減少價金請求權", "民法第348條之交付買賣標的物請求權", "合意解除契約 30840"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:28+00:00", "source_pdf_sha1": "00563b442671", "answer_pdf_sha1": "52df642a00dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "305", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00176', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-113-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '關於主物與從物之敘述，下列何者錯誤？', '["房屋非為土地之從物", "依附於第2層樓房之未具獨立性之第3層附屬建物，皆為原建築物之從物", "工廠之機器生財為該工廠之從物", "汽車之備胎為汽車之從物"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:28+00:00", "source_pdf_sha1": "00563b442671", "answer_pdf_sha1": "52df642a00dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "305", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00177', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-113-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '下列何者不屬於消滅時效之中斷事由？', '["因天災致不能行使請求權", "債權人以郵局存證信函向債務人通知債務履行", "債務人對債權人承認其權利之存在", "債權人對債務人提起民事訴訟"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:28+00:00", "source_pdf_sha1": "00563b442671", "answer_pdf_sha1": "52df642a00dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "305", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00178', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-113-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '下列何種法律行為，不屬於違反公共秩序或善良風俗而歸於無效者？', '["子女甲乙於其父母健在時預立分管合約為財產之瓜分", "有婦之夫甲誘使乙女同居，而將其所有A地之所有權移轉登記於乙女， 並約定一旦終止同居關係，須將A地返還", "甲與乙有金錢糾紛，乙則以言語恐嚇甲和解，甲於和解契約同意以分期 之方式清償債務", "夫妻甲乙間為恐一方於日後或有虐待或侮辱他方情事，而預立離婚契約"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:28+00:00", "source_pdf_sha1": "00563b442671", "answer_pdf_sha1": "52df642a00dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "305", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00179', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-113-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '關於附條件法律行為之敘述，下列何者錯誤？', '["條件之成就於法律行為成立時已確定者，倘若該條件為停止條件，認為 法律行為無條件", "條件之不成就於法律行為成立時已確定者，倘若該條件為停止條件，則 該法律行為無效", "條件之成就於法律行為成立時已確定者，倘若該條件為解除條件，則該 法律行為有效", "條件之不成就於法律行為成立時已確定者，倘若該條件為解除條件，則 該法律行為認為無條件"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:28+00:00", "source_pdf_sha1": "00563b442671", "answer_pdf_sha1": "52df642a00dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "305", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00180', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-113-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '下列何項行為，得以代理方式為之？', '["侵權行為", "發現埋藏物", "無因管理", "設定普通抵押權 30840"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:28+00:00", "source_pdf_sha1": "00563b442671", "answer_pdf_sha1": "52df642a00dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "305", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL)
